let url = "https://www.linkedin.com/jobs/search/?f_TPR=r86400&sortBy=DD&count=10";
const keyword = $input.first().json.Keyword;
const location = $input.first().json.Location;
const experienceLevel = $input.first().json['Experience Level'];
const remote = $input.first().json.Remote;
const jobType = $input.first().json['Job Type'];
const easyApply = $input.first().json['Easy Apply'];
if (keyword && keyword !== "") { url += `&keywords=${encodeURIComponent(keyword)}`; }
if (location && location !== "") { url += `&location=${encodeURIComponent(location)}`; }
if (experienceLevel && experienceLevel !== "") {
  const transformedExperiences = experienceLevel.split(",").map((exp) => {
    switch (exp.trim()) { case "Internship": return "1"; case "Entry level": return "2"; case "Associate": return "3"; case "Mid-Senior level": return "4"; case "Director": return "5"; case "Executive": return "6"; default: return ""; }
  }).filter(Boolean);
  if (transformedExperiences.length > 0) { url += `&f_E=${transformedExperiences.join(",")}`; }
}
if (remote && remote !== "") {
  const transformedRemote = remote.split(",").map((e) => {
    switch (e.trim()) { case "Remote": return "2"; case "Hybrid": return "3"; case "On-Site": return "1"; default: return ""; }
  }).filter(Boolean);
  if (transformedRemote.length > 0) { url += `&f_WT=${transformedRemote.join(",")}`; }
}
if (jobType && jobType !== "") {
  const transformedJobType = jobType.split(",").map((type) => {
    switch (type.trim()) { case "Full-time": return "F"; case "Part-time": return "P"; case "Contract": return "C"; case "Temporary": return "T"; case "Volunteer": return "V"; case "Internship": return "I"; default: return ""; }
  }).filter(Boolean);
  if (transformedJobType.length > 0) { url += `&f_JT=${transformedJobType.join(",")}`; }
}
if (easyApply === true || easyApply === "true") { url += "&f_EA=true"; }
return { url };

